class Solution {
    public long maximumOr(int[] nums, int k) {
        int n = nums.length;
        int maxValue = Long.MIN_VALUE;
        for (int i = 0; i < n; i++) {
            int currentValue = nums[i];
            for (int j = 0; j < k; j++) {
                currentValue *= 2;
            }
            maxValue = Math.max(maxValue, currentValue);
        }
        return maxValue;
    }
}
```

